
// 青春书页 — 配色
$paper: #f9f5ec;
$page: #fefcf7;
$ink: #3d3428;
$ink-faded: #8b7f6e;
$ink-light: #b8ad9e;
$accent: #c47f5a;
$accent-light: #e8cfbe;
$accent-soft: #faf2eb;
$line: #e6ddd0;
$shadow: 0 1px 4px rgba(60, 40, 20, 0.06);
$shadow-lg: 0 3px 12px rgba(60, 40, 20, 0.08);
$radius: 4px;
$radius-sm: 3px;

.opening-setup {
  font-family: 'Noto Serif SC', 'Source Han Serif SC', 'PingFang SC', 'Microsoft YaHei', system-ui, sans-serif;
  max-width: 560px;
  margin: 0 auto;
  padding: 20px 16px 28px;
  color: $ink;
  line-height: 1.7;
  background: repeating-linear-gradient(to bottom, transparent, transparent 27px, #e8e0d2 27px, #e8e0d2 28px);
  background-color: $paper;
  border-radius: 6px;
  box-shadow: 0 1px 3px rgba(50,30,10,0.04), 0 8px 24px rgba(50,30,10,0.06);
  border: 1px solid #e5dccb;
}

// ===== 标题 =====
.setup-header {
  text-align: center;
  margin-bottom: 18px;
  padding-bottom: 14px;
  border-bottom: 2px solid $line;
}
.setup-title {
  font-size: 1.4em;
  font-weight: 700;
  letter-spacing: 0.08em;
  color: $ink;
  margin: 0 0 6px;
}
.setup-subtitle {
  font-size: 0.82em;
  color: $ink-faded;
  margin: 0;
  font-style: italic;
}

// ===== 步骤条 =====
.step-bar {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0;
  margin-bottom: 16px;
}
.step-dot {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 12px;
  border-radius: 2px;
  background: transparent;
  color: $ink-light;
  font-size: 0.8em;
  transition: all 0.3s;
  &.active {
    color: $accent;
    font-weight: 600;
    border-bottom: 2px solid $accent;
  }
  &.done { color: #8a9e8a; }
}
.step-num {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.7em;
  font-weight: 700;
  background: currentColor;
  color: $page;
}
.step-text { font-size: 0.82em; letter-spacing: 0.04em; }
.step-line {
  width: 28px;
  height: 1px;
  background: $line;
  margin: 0 2px;
  &.done { background: #b5c9b5; }
}

// ===== 分区卡片 =====
.setup-section {
  background: $page;
  border-radius: $radius;
  padding: 16px 18px;
  margin-bottom: 10px;
  box-shadow: $shadow;
  border: 1px solid $line;
  position: relative;
  &::before {
    content: '';
    position: absolute;
    left: 0; top: 0; bottom: 0;
    width: 3px;
    background: linear-gradient(to bottom, transparent, $accent-light, transparent);
    border-radius: 3px 0 0 3px;
  }
}
.section-label {
  font-size: 0.88em;
  font-weight: 600;
  color: $ink;
  margin: 0 0 12px;
  display: flex;
  align-items: center;
  gap: 6px;
  letter-spacing: 0.04em;
}
.section-icon { font-size: 1.05em; opacity: 0.7; }
.section-hint {
  font-size: 0.73em;
  font-weight: 400;
  color: $ink-light;
  margin-left: auto;
  font-style: italic;
}

// ===== 字段行 =====
.field-row {
  margin-bottom: 10px;
  &:last-child { margin-bottom: 0; }
}
.field-label {
  display: block;
  font-size: 0.78em;
  font-weight: 600;
  color: $ink-faded;
  margin-bottom: 6px;
  letter-spacing: 0.04em;
}

// ===== 文本输入 =====
.text-input {
  width: 100%;
  box-sizing: border-box;
  padding: 9px 14px;
  border-radius: $radius-sm;
  border: 1px solid $line;
  background: #fdfaf4;
  color: $ink;
  font-size: 0.88em;
  font-family: inherit;
  outline: none;
  transition: border-color 0.2s;
  &::placeholder { color: $ink-light; font-style: italic; }
  &:focus {
    border-color: $accent;
    background: $page;
    box-shadow: 0 0 0 2px rgba(196, 127, 90, 0.08);
  }
}

// ===== 子区域 =====
.sub-section {
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px dotted $line;
}

// ===== 药丸 =====
.pill-row {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
}
.pill {
  font-size: 0.78em;
  padding: 5px 12px;
  border-radius: 2px;
  border: 1px solid $line;
  background: #fdfaf4;
  color: $ink;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
  white-space: nowrap;
  letter-spacing: 0.03em;
  &:hover { border-color: $accent-light; background: $accent-soft; }
  &:active { transform: scale(0.97); }
  &.active {
    border-color: $accent;
    background: $accent-soft;
    color: darken($accent, 8%);
    font-weight: 600;
    box-shadow: 0 1px 3px rgba(196, 127, 90, 0.1);
  }
}
.pill-lg { font-size: 0.83em; padding: 7px 16px; }

// ===== 系统选择卡片 =====
.sys-choice-grid {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.sys-choice-card {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 14px 16px;
  border-radius: $radius-sm;
  border: 1px solid $line;
  background: #fdfaf4;
  cursor: pointer;
  transition: all 0.22s;
  text-align: left;
  user-select: none;
  &:hover {
    border-color: $accent-light;
    background: $accent-soft;
    transform: translateX(3px);
  }
  &:active { transform: translateX(1px); }
  &.active {
    border-color: $accent;
    background: $accent-soft;
    box-shadow: 0 2px 8px rgba(196, 127, 90, 0.1);
    .sys-choice-name { color: darken($accent, 6%); }
  }
}
.sys-choice-icon {
  font-size: 1.5em;
  flex-shrink: 0;
  line-height: 1;
  margin-top: 2px;
  opacity: 0.8;
}
.sys-choice-info {
  flex: 1; min-width: 0;
  display: flex; flex-direction: column; gap: 3px;
}
.sys-choice-name {
  font-size: 0.88em; font-weight: 600; color: $ink;
  transition: color 0.2s; letter-spacing: 0.03em;
}
.sys-choice-desc {
  font-size: 0.76em; color: $ink-faded; line-height: 1.5;
}

// ===== 未完待续 =====
.tbc-text {
  text-align: center;
  font-size: 0.75em;
  color: $ink-light;
  letter-spacing: 0.1em;
  margin: 6px 0 2px;
  user-select: none;
  font-style: italic;
}

// ===== 预览 =====
.preview-card {
  background: #fdfaf4;
  border-color: #e8e0d2;
  &::before { display: none; }
}
.preview-content {
  margin: 0;
  font-size: 0.8em;
  line-height: 1.7;
  color: $ink-faded;
  font-family: inherit;
  white-space: pre-wrap;
  word-break: break-all;
}

// ===== 按钮 =====
.setup-actions {
  display: flex;
  gap: 10px;
  margin-top: 14px;
}
.btn-primary {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: $radius-sm;
  border: none;
  background: $accent;
  color: #fff;
  font-size: 0.95em;
  font-weight: 600;
  font-family: inherit;
  letter-spacing: 0.06em;
  cursor: pointer;
  transition: all 0.22s;
  box-shadow: 0 2px 8px rgba(196, 127, 90, 0.25);
  &:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: 0 4px 14px rgba(196, 127, 90, 0.3);
  }
  &:active:not(:disabled) {
    transform: translateY(0);
    box-shadow: 0 1px 4px rgba(196, 127, 90, 0.2);
  }
  &:disabled {
    opacity: 0.4;
    cursor: not-allowed;
    box-shadow: none;
  }
  svg { flex-shrink: 0; }
}
.btn-random {
  padding: 12px 16px;
  border-radius: $radius-sm;
  border: 1px solid $line;
  background: $page;
  color: $ink-faded;
  font-size: 0.85em;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
  box-shadow: $shadow;
  &:hover { border-color: $accent-light; background: $accent-soft; color: $ink; }
  &:active { transform: scale(0.97); }
}
.btn-back {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 12px 16px;
  border-radius: $radius-sm;
  border: 1px solid $line;
  background: $page;
  color: $ink-faded;
  font-size: 0.85em;
  font-family: inherit;
  cursor: pointer;
  transition: all 0.2s;
  box-shadow: $shadow;
  svg { transform: rotate(180deg); flex-shrink: 0; }
  &:hover { border-color: $accent-light; background: $accent-soft; color: $ink; }
  &:active { transform: scale(0.97); }
}
